// // (1) set: Clears flip-flop to zero. Synchronous active high.
// (2) reset: Sets flip-flop to one. Synchronous active high.
module top_module(
	input clk,
	input set,
	input reset,
	input j,
	input k,
	output reg q);always @(posedge clk) begin
	if (reset)
		q <= 1'b0;
	else if (set)
		q <= 1'b1;
	else if (j && ~k)
		q <= 1'b1;
	else if (~j && k)
		q <= 1'b0;
	else if (j && k)
		q <= ~q;
end
endmodule
